+        }
+
+        let target = self.session.try_lock().ok().and_then(|guard| {
+            let (_, branches) = guard.sibling_branches()?;
+            if branches.len() <= 1 {
+                return None;
+            }
+            let current_idx = branches.iter().position(|b| b.is_current)?;
+            let next_idx = if forward {
+                (current_idx + 1) % branches.len()
